IF OBJECT_ID(N'POC.PUR_POH',N'U') IS NULL CREATE TABLE POC.PUR_POH (CD_FIRM varchar(10) NOT NULL,NO_PO varchar(30) NOT NULL,DT_PO date NOT NULL,CD_PARTNER varchar(20) NOT NULL,NM_PARTNER nvarchar(100) NOT NULL,CD_EMP varchar(20) NOT NULL,NM_EMP nvarchar(100) NULL,CD_CURRENCY varchar(10) NOT NULL,RT_EXCHANGE decimal(19,6) NOT NULL,ST_PO varchar(20) NOT NULL,DC_RMK nvarchar(1000) NOT NULL DEFAULT N'',CD_USER_REG varchar(50) NOT NULL,TM_REG datetime2 NOT NULL,CD_USER_AMD varchar(50) NULL,TM_AMD datetime2 NULL,CONSTRAINT PK_PUR_POH PRIMARY KEY(CD_FIRM,NO_PO),CONSTRAINT FK_PUR_POH_PARTNER FOREIGN KEY(CD_FIRM,CD_PARTNER) REFERENCES POC.MA_PARTNER(CD_FIRM,CD_PARTNER));
IF OBJECT_ID(N'POC.PUR_POL',N'U') IS NULL CREATE TABLE POC.PUR_POL (CD_FIRM varchar(10) NOT NULL,NO_PO varchar(30) NOT NULL,NO_LINE int NOT NULL,CD_ITEM varchar(30) NOT NULL,NM_ITEM nvarchar(100) NOT NULL,STND_ITEM nvarchar(100) NOT NULL,UNIT_ITEM varchar(10) NOT NULL,QT_PO decimal(19,4) NOT NULL,UM_PO decimal(19,4) NOT NULL,AM_SUPPLY decimal(19,4) NOT NULL,AM_VAT decimal(19,4) NOT NULL,AM_TOTAL decimal(19,4) NOT NULL,DT_DLV date NOT NULL,CD_WH varchar(20) NOT NULL,NM_WH nvarchar(100) NOT NULL,DC_RMK nvarchar(1000) NOT NULL DEFAULT N'',CD_USER_REG varchar(50) NOT NULL,TM_REG datetime2 NOT NULL,CD_USER_AMD varchar(50) NULL,TM_AMD datetime2 NULL,CONSTRAINT PK_PUR_POL PRIMARY KEY(CD_FIRM,NO_PO,NO_LINE),CONSTRAINT FK_PUR_POL_POH FOREIGN KEY(CD_FIRM,NO_PO) REFERENCES POC.PUR_POH(CD_FIRM,NO_PO),CONSTRAINT FK_PUR_POL_ITEM FOREIGN KEY(CD_FIRM,CD_ITEM) REFERENCES POC.MA_ITEM(CD_FIRM,CD_ITEM),CONSTRAINT FK_PUR_POL_WH FOREIGN KEY(CD_FIRM,CD_WH) REFERENCES POC.MA_WH(CD_FIRM,CD_WH));
IF NOT EXISTS(SELECT 1 FROM sys.indexes WHERE name=N'IX_PUR_POH_SEARCH' AND object_id=OBJECT_ID(N'POC.PUR_POH')) CREATE INDEX IX_PUR_POH_SEARCH ON POC.PUR_POH(CD_FIRM,DT_PO,CD_PARTNER,ST_PO);
